import React, { useRef, useState } from "react";
import { Button, Grid, Input, Row, Textarea } from "@nextui-org/react";
import confetti from "canvas-confetti";

export default function ContactForm() {
  const [name, setName] = useState("");
  const [email, setEmail] = useState("");
  const [msg, setMsg] = useState("");
  const [nameErr, setNameErr] = useState(false);
  const [emailErr, setEmailErr] = useState(false);
  const [msgErr, setMsgErr] = useState(false);
  const [submit, setSubmit] = useState(false);

  const formRef = useRef(null)

  const handleConfetti = () => {
    confetti({
      particleCount: 150,
      spread: 360,
      origin: {
        x: Math.random(),
        // since they fall down, start a bit higher than random
        y: Math.random() - 0.2,
      },
    });
  };

  function handleSubmit() {
    if (name == "") {
      setNameErr(true);
    }
    if (email == "") {
      setEmailErr(true);
    }
    if (msg == "") {
      setMsgErr(true);
    }
    if (name != "" && email != "" && msg != "") {
      setNameErr(false);
      setEmailErr(false);
      setMsgErr(false);
      setSubmit(true);
      handleConfetti();
    }
  }

  return (
    <Grid.Container gap={2} css={{ height: "max-content" }}>
      <Grid xs={12} sm={6}>
        <Row align="flex-start" css={{ mt: "20px" }}>
          <Input
            underlined
            labelPlaceholder="Name"
            color="secondary"
            fullWidth={true}
            required
            type={"text"}
            helperText={nameErr ? "Enter Your Name" : ""}
            value={name}
            onChange={(e) => {
              setName(e.target.value);
              setNameErr(false);
            }}
          />
        </Row>
      </Grid>
      <Grid xs={12} sm={6}>
        <Row align="flex-start" css={{ mt: "20px" }}>
          <Input
            underlined
            labelPlaceholder="Email"
            fullWidth={true}
            color="secondary"
            type={"email"}
            required
            value={email}
            helperText={emailErr ? "Enter Your Email" : ""}
            onChange={(e) => {
              setEmail(e.target.value);
              setEmailErr(false);
            }}
          />
        </Row>
      </Grid>
      <Grid xs={12} sm={12}>
        <Row align="flex-start" css={{ mt: "20px" }}>
          <Textarea
            underlined
            color="secondary"
            fullWidth={true}
            labelPlaceholder="Message"
            helperText={msgErr ? "Enter Your Message" : ""}
            value={msg}
            required
            onChange={(e) => {
              setMsg(e.target.value);
              setMsgErr(false);
            }}
          />
        </Row>
      </Grid>
      <Grid xs={12} sm={12}>
        <Row align="flex-start" css={{ mt: "20px" }}>
          <Button
            color={"gradient"}
            size="sm"
            auto
            disabled={submit ? true : false}
            onClick={handleSubmit}
          >
            {submit ? "Submitted" : "Submit"}
          </Button>
        </Row>
      </Grid>
      <div className="hidden">
        <form
          action="https://postmail.invotes.com/send"
          method="post"
          id="email_form"
        >
          <input type="text" name="subject" value={name} />
          <input type="text" name="reply_to" value={email} />
          <textarea name="text">{msg}</textarea>
          <input
            type="hidden"
            name="access_token"
            value="z1amhl8spalh7myr86l1a3az"
          />
          <input
            type="hidden"
            name="success_url"
            value=".?message=Email+Successfully+Sent%21&isError=0"
          />
          <input
            type="hidden"
            name="error_url"
            value=".?message=Email+could+not+be+sent.&isError=1"
          />
          <input id="submit_form" type="submit" value="Send" />
          <p>
            Powered by{" "}
            <a href="https://postmail.invotes.com" target="_blank">
              PostMail
            </a>
          </p>
        </form>
      </div>
    </Grid.Container>
  );
}
